var formatIDR = (value) => new Intl.NumberFormat("id-ID").format(value || 0);
function formatPrice(value, mode, kursUsd = 16004, kursEur = 17500) {
  const n2 = Number(value) || 0;
  if (mode === "USD") return `$ ${(n2 / kursUsd).toFixed(2)}`;
  if (mode === "EUR") return `\u20AC ${(n2 / kursEur).toFixed(2)}`;
  return `Rp ${formatIDR(n2)}`;
}

