// src/utils/treeHelpers.js
var flattenTree = (node2, level = 0, isLast = true, result = []) => {
  result.push({ id: node2.id, level, isLast, data: node2 });
  if (node2.children) {
    node2.children.forEach((child, idx) => {
      flattenTree(child, level + 1, idx === node2.children.length - 1, result);
    });
  }
  return result;
};
function getAncestorChain(root, targetId, trail = []) {
  if (!root) return null;
  if (root.id === targetId) return trail;
  for (const child of root.children || []) {
    const hit = getAncestorChain(child, targetId, [...trail, root]);
    if (hit) return hit;
  }
  return null;
}
function getPartHierarchyLabels(root, partId) {
  const chain = getAncestorChain(root, partId) || [];
  const pick = (tipe) => chain.find((n2) => n2.tipe === tipe);
  return {
    modul: pick("MODUL"),
    submodul: pick("SUBMODUL"),
    submodul2: pick("SUBMODUL 2")
  };
}

