var CONTAINER_PRESETS = [
  {
    id: "1piece",
    type: "1 piece",
    boxFromVolume: true,
    sfFromVolume: true,
    unitBox: "m\xB3",
    unitSF: "m\xB3"
  },
  {
    id: "20foot",
    type: "20 foot",
    containerNetM3: CONTAINER_NET_VOLUME_M3["20foot"],
    unitBox: "Pcs",
    unitSF: "Pcs"
  },
  {
    id: "40foot",
    type: "40 foot",
    containerNetM3: CONTAINER_NET_VOLUME_M3["40foot"],
    unitBox: "Pcs",
    unitSF: "Pcs"
  },
  {
    id: "40hc",
    type: "40 foot HC",
    containerNetM3: CONTAINER_NET_VOLUME_M3["40hc"],
    unitBox: "Pcs",
    unitSF: "Pcs"
  }
];
function calcPackingVolume(dimensi, packingItem, options = {}) {
  if (!packingItem || !dimensi) return 0;
  const w2 = (Number(dimensi.w) || 0) + (Number(packingItem.tolW) || 0);
  const d2 = (Number(dimensi.d) || 0) + (Number(packingItem.tolD) || 0);
  const h3 = (Number(dimensi.h) || 0) + (Number(packingItem.tolH) || 0);
  let vol = w2 * d2 * h3 / 1e9;
  const itemType = options.itemType ?? "";
  if (packingItem.chairFactor && String(itemType).toUpperCase() === "CHAIR") {
    vol *= 0.6;
  }
  return Number(vol.toFixed(6));
}
function calcContainerNetCapacity(preset, volBox, volSF) {
  const boxVol = Number(volBox) || 0;
  const sfVol = Number(volSF) || 0;
  if (preset.boxFromVolume) {
    return {
      netCapBox: Number(boxVol.toFixed(6)),
      netCapSF: Number(sfVol.toFixed(6))
    };
  }
  const containerM3 = Number(preset.containerNetM3) || 0;
  const pcsFromVol = (pieceVol) => {
    if (!pieceVol || !containerM3) return 0;
    return Math.floor(containerM3 / pieceVol);
  };
  return {
    netCapBox: pcsFromVol(boxVol),
    netCapSF: sfVol ? pcsFromVol(sfVol) : 0
  };
}
function buildDefaultContainerRows(volBox = 0, volSF = 0) {
  return CONTAINER_PRESETS.map((p3) => {
    const caps = calcContainerNetCapacity(p3, volBox, volSF);
    return {
      presetId: p3.id,
      type: p3.type,
      netCapBox: caps.netCapBox,
      netCapSF: caps.netCapSF,
      matCostBox: 0,
      matCostSF: 0,
      routCostBox: 0,
      routCostSF: 0,
      mgtOvBox: 0,
      mgtOvSF: 0,
      totalBox: 0,
      totalSF: 0,
      hidden: false
    };
  });
}
function findPackingByType(packingDimensions, keyword) {
  const key = keyword.toLowerCase();
  return packingDimensions.find((p3) => p3.type?.toLowerCase().includes(key));
}

